examples.code:
// Guardar y leer un valor simple
localStorage.setItem('idioma', 'es');
localStorage.setItem('tema', 'oscuro');

const idioma = localStorage.getItem('idioma');
const tema = localStorage.getItem('tema');

console.log(idioma); // 'es'
console.log(tema);   // 'oscuro'

// Leer clave que no existe
const noExiste = localStorage.getItem('xyz');
console.log(noExiste); // null

// Guardar un objeto usando JSON
const usuario = { nombre: 'Ana', nivel: 3, xp: 1250 };

// Guardar: objeto → string
localStorage.setItem('usuario', JSON.stringify(usuario));

// Leer: string → objeto
const texto = localStorage.getItem('usuario');
const usuarioRecuperado = JSON.parse(texto);

console.log(usuarioRecuperado.nombre); // 'Ana'
console.log(usuarioRecuperado.xp);    // 1250

// Patrón seguro: leer con valor por defecto
function leerODefault(clave, valorDefault) {
  const texto = localStorage.getItem(clave);
  if (texto === null) return valorDefault;
  try {
    return JSON.parse(texto);
  } catch {
    return valorDefault;
  }
}

const tema = leerODefault('tema', 'claro');
const puntos = leerODefault('puntos', 0);

console.log(tema);   // 'claro' (si no había nada guardado)
console.log(puntos); // 0

